        var containsInitialBatchBuilder = source.Contains("Then call BuildInitialDiscoveryBatch(proposedQuestionsJson, askedQuestionsJson, {{DiscoveryFlowLimits.InitialBatchSize}}).", StringComparison.Ordinal);
        var containsSingleFollowUpRoundCap = source.Contains("Maximum follow-up rounds: {{DiscoveryFlowLimits.MaxFollowUpRounds}}.", StringComparison.Ordinal);
