        var containsMandatoryCallOrder = source.Contains("Mandatory call order for each discovery turn (do not reorder, do not skip):", StringComparison.Ordinal);
        var buildInitialAppearsOnce = source.Split("Before calling BuildInitialDiscoveryBatch").Length - 1 == 1;

        var contactAgentStart = source.IndexOf("name: \"contact_collection_agent\"", StringComparison.Ordinal);
        var discoveryBuilderPosition = source.IndexOf("Before calling BuildInitialDiscoveryBatch", StringComparison.Ordinal);
        var discoveryBuilderOnlyInDiscoverySection = discoveryBuilderPosition >= 0
            && contactAgentStart > 0
            && discoveryBuilderPosition < contactAgentStart;

        var containsSummaryCompositionTool = source.Contains("Call evaluate_summary_composition before drafting the summary", StringComparison.Ordinal);
        var containsDistilledNarrativeRule = source.Contains("If DistilledNarrativeOnly=true, keep the narrative distilled", StringComparison.Ordinal);
