        Assert.True(containsSingleFollowUpRoundCap);
        Assert.True(containsBatchPersistTool);
        Assert.True(containsDeterministicParserTool);
        Assert.True(containsDeterministicPayloadBuilder);
        Assert.True(containsDeterministicTransitionTool);
        Assert.True(containsMandatoryCallOrder);
        Assert.True(buildInitialAppearsOnce);
        Assert.True(discoveryBuilderOnlyInDiscoverySection);
        Assert.True(containsSummaryCompositionTool);
        Assert.True(containsDistilledNarrativeRule);
        Assert.True(containsConditionalUnknownsRule);
